// String sempre tem valor — o compilador garante isso
var nome: String = "Jessica"

// String? pode ser nil — você declara essa possibilidade
var apelido: String? = nil
var cidade: String? = "São Paulo"

// Isso NÃO compila — Swift detecta o erro antes de rodar:
// nome = nil  ← erro: 'nil' cannot be assigned to type 'String'

var apelido: String? = nil

// PERIGO — vai crashar em runtime:
print(apelido!)  // Fatal error: Unexpectedly found nil while unwrapping an Optional value

// Só é aceitável quando você TEM certeza absoluta:
let url = URL(string: "https://apple.com")!  // URL conhecida e válida

var apelido: String? = "Jess"

// Forma clássica:
if let nome = apelido {
    print("Olá, \(nome)")  // nome é String, não String?
} else {
    print("Sem apelido")
}

// Swift moderno — reutiliza o mesmo nome:
if let apelido {
    print("Apelido: \(apelido)")  // apelido aqui é String
}

// Encadeando dois optionals:
if let nome = usuario.nome, let email = usuario.email {
    print("\(nome) — \(email)")  // só executa se ambos tiverem valor
}

// Sem guard — código aninhado que cresce para a direita:
func processar(usuario: Usuario?) {
    if let usuario = usuario {
        if let email = usuario.email {
            if email.contains("@") {
                print("Email válido: \(email)")
            }
        }
    }
}

// Com guard — linear e mais fácil de ler:
func processar(usuario: Usuario?) {
    guard let usuario else { return }       // sai se nil
    guard let email = usuario.email else { return }  // sai se nil
    guard email.contains("@") else { return }        // sai se inválido

    print("Email válido: \(email)")  // código feliz, linear
}

var apelido: String? = nil
var nomeCompleto: String? = "Jessica Serqueira"

// Usa apelido, ou "Anônimo" se for nil:
let textoExibido = apelido ?? "Anônimo"
print(textoExibido)  // "Anônimo"

// Encadeando três fontes:
let exibir = apelido ?? nomeCompleto ?? "Visitante"
print(exibir)  // "Jessica Serqueira" — segundo tenta quando primeiro é nil

// Direto na View SwiftUI:
struct PerfilView: View {
    let usuario: Usuario

    var body: some View {
        Text(usuario.apelido ?? usuario.nome ?? "Sem nome")
    }
}

struct Endereco {
    var cidade: String
    var cep: String?
}

struct Usuario {
    var nome: String
    var endereco: Endereco?
}

var usuario: Usuario? = Usuario(nome: "Jess", endereco: nil)

// Sem optional chaining — ifs aninhados:
var cidade = "Desconhecida"
if let u = usuario {
    if let end = u.endereco {
        cidade = end.cidade
    }
}

// Com optional chaining — direto e limpo:
let cidadeExibida = usuario?.endereco?.cidade ?? "Desconhecida"
print(cidadeExibida)  // "Desconhecida" — sem crash

// Chamar métodos também funciona:
let cidadeMaiuscula = usuario?.endereco?.cidade.uppercased() ?? "DESCONHECIDA"

// struct — cópia independente:
struct Ponto {
    var x: Int
    var y: Int
}

var a = Ponto(x: 1, y: 2)
var b = a    // b é uma CÓPIA
b.x = 99
print(a.x)   // 1 — a não foi afetado

// class — referência compartilhada:
class Contador {
    var valor: Int = 0
}

var c1 = Contador()
var c2 = c1    // c2 aponta para o MESMO objeto
c2.valor = 99
print(c1.valor)  // 99 — c1 foi afetado também

// Definindo um protocol:
protocol Saudavel {
    var calorias: Int { get }  // precisa ter essa propriedade
    func descricao() -> String  // precisa ter esse método
}

// Qualquer tipo que "adote" esse protocol precisa implementar tudo:
struct Fruta: Saudavel {
    var nome: String
    var calorias: Int  // obrigatório — compilador avisa se faltar

    func descricao() -> String {  // obrigatório
        return "\(nome): \(calorias) kcal"
    }
}

// View é um protocol com um único requisito:
protocol View {
    associatedtype Body: View
    var body: Self.Body { get }
}

// Sua struct cumpre o contrato:
struct MinhaView: View {  // adota o protocol View
    var body: some View { // cumpre o requisito
        Text("Olá")
    }
}

// Identifiable exige uma propriedade id:
protocol Identifiable {
    associatedtype ID: Hashable
    var id: Self.ID { get }
}

// Sua struct adota Identifiable:
struct Tarefa: Identifiable {
    let id: UUID  // UUID garante unicidade
    var titulo: String
    var concluida: Bool

    // Swift gera UUID automaticamente se você quiser:
    init(titulo: String) {
        self.id = UUID()
        self.titulo = titulo
        self.concluida = false
    }
}

// ForEach usa Identifiable automaticamente:
ForEach(tarefas) { tarefa in  // tarefa é Identifiable
    Text(tarefa.titulo)
}

// Equatable — pode comparar com ==
struct Cor: Equatable {
    var vermelho: Double
    var verde: Double
    var azul: Double
    // Swift gera == automaticamente para structs
}

let corA = Cor(vermelho: 1.0, verde: 0.0, azul: 0.0)
let corB = Cor(vermelho: 1.0, verde: 0.0, azul: 0.0)
print(corA == corB)  // true

// Hashable — pode ir em Set ou ser chave de dicionário
enum Tela: Hashable {
    case inicio
    case detalhes(id: UUID)
    case configuracoes
}

// NavigationStack usa Hashable para o path:
NavigationStack(path: $rota) {
    // rota pode ser [Tela]
}

// Sem generics — precisaria uma função por tipo:
func primeiroInt(_ array: [Int]) -> Int? { array.first }
func primeiroString(_ array: [String]) -> String? { array.first }

// Com generics — uma função para tudo:
func primeiro<T>(_ array: [T]) -> T? {
    array.first
}

let num = primeiro([1, 2, 3])       // T = Int
let texto = primeiro(["a", "b"])    // T = String

// Array já é genérico:
var numeros: Array<Int> = [1, 2, 3]
var textos: Array<String> = ["a", "b"]  // mesmo tipo, T diferente

// Sem some View — tipo gigante e impraticável:
var body: ModifiedContent<Text, _PaddingLayout> {
    Text("Olá").padding()
}

// Com some View — compilador resolve internamente:
var body: some View {
    Text("Olá").padding()
}

// AnyView apaga o tipo — evite quando possível:
func icone(carregado: Bool) -> AnyView {
    if carregado {
        return AnyView(Image(systemName: "star"))
    } else {
        return AnyView(ProgressView())
    }
}

// Preferível — usa @ViewBuilder que mantém o tipo:
@ViewBuilder
func icone(carregado: Bool) -> some View {
    if carregado {
        Image(systemName: "star")
    } else {
        ProgressView()
    }
}
